var app = builder.Build();
app.MapGet("/", () => "Hello");
app.Run();

arguments.new_str:
using Microsoft.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);

// Train and save the model at startup
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");

var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(split.TrainSet);

// Evaluate on held-out test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions);
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, F1: {metrics.F1Score:F4}, Accuracy: {metrics.Accuracy:F4}");

// Save model and register pooled prediction engine (thread-safe)
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");
mlContext.Model.Save(model, dataView.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (
    PredictionEnginePool<CustomerData, ChurnPrediction> pool,
    CustomerRequest request) =>
{
    var input = new CustomerData
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region,
        PurchaseHistory = request.PurchaseHistory,
    };

    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        churned = prediction.Churned,
        probability = prediction.Probability,
    });
});

app.Run();

record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

